    // --- Composed function helpers (Q128.128) ---

    fn multiply_q128(a: I256, b: I256) -> I256 {
        let neg = a.is_negative() ^ b.is_negative();
        let abs_a = if a.is_negative() { -a } else { a };
        let abs_b = if b.is_negative() { -b } else { b };
        let product = abs_a.mul_to_i512(abs_b);
        let shifted = product >> 128;
        let result = shifted.as_i256();
        if neg { -result } else { result }
    }

    fn divide_q128(dividend: I256, divisor: I256) -> I256 {
        if divisor == I256::zero() {
            let max_val = i256_from_words([u64::MAX, u64::MAX, u64::MAX, u64::MAX >> 1]);
            return if dividend.is_negative() { -max_val } else { max_val };
        }
        let wide_a = I512::from_i256(dividend) << 128;
        let wide_b = I512::from_i256(divisor);
        let quotient = wide_a / wide_b;
        quotient.as_i256()
    }

    fn halve_q128(x: I256) -> I256 { x >> 1 }

    fn one_q128() -> I256 { i256_from_words([0, 0, 1, 0]) }

