    #[test]
    fn validate_acos_ulp() {
        // acos(x) = pi/2 - asin(x)
        let pi_half = pi_half_i512();
        let one = one_q256();
        let mut max_ulp = I512::zero();
        let mut worst_label = "";
        for &(input_w, expected_w, label) in ACOS_REFS.iter() {
            let input = i512_from_words(input_w);
            let expected = i512_from_words(expected_w);
            let x_sq = multiply_q256(input, input);
            let sq = sqrt_binary_i512(one - x_sq);
            let ratio = if sq == I512::zero() {
                let max_val = i512_from_words([u64::MAX, u64::MAX, u64::MAX, u64::MAX,
                                               u64::MAX, u64::MAX, u64::MAX, u64::MAX >> 1]);
                if input.is_negative() { -max_val } else { max_val }
            } else {
                divide_q256(input, sq)
            };
            let asin_val = atan_binary_i512(ratio);
            let actual = pi_half - asin_val;
            let ulp = ulp_i512(actual, expected);
            max_ulp = max_ulp_i512(max_ulp, ulp);
            if ulp == max_ulp { worst_label = label; }
        }
        eprintln!("acos Q256.256: max ULP={} across {} points (worst: {})",
            format_i512_hex(max_ulp), ACOS_REFS.len(), worst_label);
    }

